import { RouteProp, useNavigation, useRoute } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useEffect, useState } from 'react';
import { ActivityIndicator, Pressable, SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { formatCurrency, formatOrderNumber } from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { getOrderById, OrderRecord } from '../services/firebaseService';

type RouteProps = RouteProp<RootStackParamList, 'OrderConfirmed'>;
type NavigationProp = NativeStackNavigationProp<RootStackParamList>;

const OrderConfirmedScreen = () => {
  const route = useRoute<RouteProps>();
  const navigation = useNavigation<NavigationProp>();
  const [order, setOrder] = useState<OrderRecord | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;
    const loadOrder = async () => {
      const data = await getOrderById(route.params.orderId);
      if (active) {
        setOrder(data);
        setLoading(false);
      }
    };
    loadOrder();
    return () => {
      active = false;
    };
  }, [route.params.orderId]);

  if (loading) {
    return (
      <SafeAreaView style={styles.loaderContainer}>
        <ActivityIndicator size="large" color="#0D8DD8" />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <View style={styles.illustrationWrap}>
          <View style={styles.dropOuter}>
            <View style={styles.dropInner} />
          </View>
        </View>
        <Text style={styles.title}>Your water can order has been placed successfully</Text>
        <Text style={styles.subtitle}>
          The delivery team has received your booking and will update the status step by step.
        </Text>

        <View style={styles.summaryCard}>
          <Text style={styles.summaryLabel}>Order ID</Text>
          <Text style={styles.summaryValue}>{formatOrderNumber(order)}</Text>
          <Text style={styles.summaryLabel}>Expected delivery time</Text>
          <Text style={styles.summaryValue}>{order?.expectedDeliveryTime || 'Today, 30-45 min'}</Text>
          <Text style={styles.summaryLabel}>Amount</Text>
          <Text style={styles.summaryValue}>{formatCurrency(order?.totalAmount ?? 0)}</Text>
        </View>

        <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('OrderTracking', { orderId: order?.id })}>
          <Text style={styles.primaryButtonText}>Track Order</Text>
        </Pressable>
        <Pressable style={styles.secondaryButton} onPress={() => navigation.navigate('NewOrder', { reorder: true })}>
          <Text style={styles.secondaryButtonText}>Order Again</Text>
        </Pressable>
        <Pressable style={styles.textButton} onPress={() => navigation.navigate('CustomerHome')}>
          <Text style={styles.textButtonText}>Go Home</Text>
        </Pressable>
      </View>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF',
    justifyContent: 'center',
    padding: 18
  },
  loaderContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#F2F9FF'
  },
  card: {
    backgroundColor: 'white',
    borderRadius: 30,
    padding: 24
  },
  illustrationWrap: {
    alignItems: 'center'
  },
  dropOuter: {
    width: 104,
    height: 104,
    borderRadius: 52,
    backgroundColor: '#DFF4FF',
    alignItems: 'center',
    justifyContent: 'center'
  },
  dropInner: {
    width: 54,
    height: 54,
    borderRadius: 27,
    backgroundColor: '#0D8DD8'
  },
  title: {
    marginTop: 22,
    color: '#10324A',
    fontSize: 28,
    fontWeight: '900',
    textAlign: 'center',
    lineHeight: 36
  },
  subtitle: {
    marginTop: 12,
    color: '#5E788C',
    fontSize: 15,
    lineHeight: 23,
    textAlign: 'center'
  },
  summaryCard: {
    marginTop: 22,
    borderRadius: 24,
    backgroundColor: '#F6FBFF',
    padding: 18
  },
  summaryLabel: {
    color: '#6D8699',
    fontSize: 12,
    fontWeight: '700',
    textTransform: 'uppercase',
    marginTop: 10
  },
  summaryValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 18,
    fontWeight: '800'
  },
  primaryButton: {
    marginTop: 20,
    backgroundColor: '#0D8DD8',
    borderRadius: 20,
    paddingVertical: 16,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: 'white',
    fontSize: 17,
    fontWeight: '900'
  },
  secondaryButton: {
    marginTop: 12,
    backgroundColor: '#EAF7FF',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  secondaryButtonText: {
    color: '#0D63A8',
    fontSize: 16,
    fontWeight: '800'
  },
  textButton: {
    marginTop: 12,
    alignItems: 'center',
    paddingVertical: 10
  },
  textButtonText: {
    color: '#0D63A8',
    fontSize: 15,
    fontWeight: '800'
  }
});

export default OrderConfirmedScreen;
